import React, { useEffect, useState } from 'react';
import fileService from '../services/fileService';
function DownloadManager(){
  const [files, setFiles] = useState([]);
  const [passkeyById, setPasskeyById] = useState({});
  const [previewId, setPreviewId] = useState(null); // show inline preview for fileId
  useEffect(()=>{ (async()=>{ try{ const res = await fileService.getSharedFiles(); setFiles(res); }catch(e){ console.error(e); } })(); },[]);
  const download=async(id)=>{
    try{
      const passkey = passkeyById[id] || '';
      if(!passkey) return alert('Enter passkey');
      const coords = await new Promise(resolve => {
        if (!navigator.geolocation) return resolve(null);
        navigator.geolocation.getCurrentPosition(
          p => resolve({ lat: p.coords.latitude, lng: p.coords.longitude }),
          () => resolve(null),
          { enableHighAccuracy: true, timeout: 5000 }
        );
      });
      await fileService.downloadWithPasskey(id, passkey, coords);
    }catch(e){
      try{
        // Axios may give a Blob for error responses with responseType:'blob'
        if(e?.response?.data instanceof Blob){
          const text = await e.response.data.text();
          try{
            const json = JSON.parse(text);
            alert(json.error || 'Failed');
          }catch{
            alert(text || 'Failed');
          }
        } else {
          alert(e?.response?.data?.error || e?.message || 'Failed');
        }
      }catch{
        alert('Failed');
      }
    }
  };
  // Viewer component for inline preview
  function SharedFileViewer({ fileId, originalname, passkey }){
    const [blobUrl, setBlobUrl] = useState('');
    const [contentType, setContentType] = useState('');
    const [error, setError] = useState('');
    useEffect(() => {
      (async () => {
        try {
          const coords = await new Promise(resolve => {
            if (!navigator.geolocation) return resolve(null);
            navigator.geolocation.getCurrentPosition(
              p => resolve({ lat: p.coords.latitude, lng: p.coords.longitude }),
              () => resolve(null),
              { enableHighAccuracy: true, timeout: 5000 }
            );
          });
          const res = await fileService.viewFile(fileId, passkey, coords);
          const ct = res.headers['content-type'] || '';
          setContentType(ct);
          const url = window.URL.createObjectURL(new Blob([res.data], { type: ct }));
          setBlobUrl(url);
        } catch (err) {
          try{
            if (err?.response?.data instanceof Blob) {
              const text = await err.response.data.text();
              try {
                const json = JSON.parse(text);
                setError(json.error || 'Failed to load preview');
              } catch {
                setError(text || 'Failed to load preview');
              }
            } else {
              setError(err?.response?.data?.error || err?.message || 'Failed to load preview');
            }
          } catch {
            setError('Failed to load preview');
          }
        }
      })();
      // eslint-disable-next-line
    }, [fileId, passkey]);
    const canEmbed = contentType.startsWith('application/pdf') || contentType.startsWith('image/');
    const canGoogleDoc = contentType.startsWith('application/msword') || contentType.startsWith('application/vnd.openxmlformats-officedocument.wordprocessingml.document');
    const isText = contentType.startsWith('text/plain');
    return (
      <div className="mt-2 mb-6">
        {error && <div className="text-red-600 text-sm">{error}</div>}
        {blobUrl && canEmbed && contentType.startsWith('application/pdf') && (
          <iframe title="pdf-viewer" src={blobUrl} className="w-full" style={{height:'60vh', border:'1px solid #e0e7ef'}} />
        )}
        {blobUrl && canEmbed && contentType.startsWith('image/') && (
          <img src={blobUrl} alt="Preview" className="max-w-full max-h-[60vh] mx-auto rounded" />
        )}
        {blobUrl && canGoogleDoc && (
          <iframe title="word-viewer" src={`https://docs.google.com/gview?url=${encodeURIComponent(blobUrl)}&embedded=true`} className="w-full" style={{height:'60vh', border:'1px solid #e0e7ef'}} />
        )}
        {/* For text/plain, render text in pre / code */}
        {blobUrl && isText && <pre className="bg-gray-100 border rounded p-4 max-h-[60vh] overflow-auto">{'(Text preview)\n'}{blobUrl}</pre>}
        {blobUrl && !canEmbed && !canGoogleDoc && !isText && <div className="text-gray-700">Cannot preview this file type. Download to open.</div>}
      </div>
    );
  }
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-100 flex flex-col items-center p-8">
      <div className="w-full max-w-4xl bg-white rounded-2xl shadow-lg p-8">
        <h2 className="text-3xl font-bold mb-6 text-blue-700">Files Shared With Me</h2>
        <div className="mb-3 text-sm text-gray-600">Depending on your access, you may only view, or also download/share the file.</div>
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white rounded-lg shadow border">
            <thead className="bg-blue-100">
              <tr>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">File ID</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Name</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Owner</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Role</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Action</th>
              </tr>
            </thead>
            <tbody>
              {files.map(f => (
                <React.Fragment key={f.file_id}>
                <tr className="border-t hover:bg-blue-50 transition">
                  <td className="py-2 px-4">{f.file_id}</td>
                  <td className="py-2 px-4">{f.originalname}</td>
                  <td className="py-2 px-4">{f.owner_email}</td>
                  <td className="py-2 px-4">{f.role}</td>
                  <td className="py-2 px-4">
                    <div className="flex items-center gap-2">
                      {(f.role === 'download' || f.role === 'share') ? (
                        <>
                          <input type="password" placeholder="Passkey" value={passkeyById[f.file_id]||''} onChange={e=>setPasskeyById({...passkeyById,[f.file_id]:e.target.value})} className="border p-1 rounded" />
                          <button onClick={() => setPreviewId(previewId === f.file_id ? null : f.file_id)} className="bg-blue-500 text-white px-3 py-1 rounded-lg shadow hover:bg-blue-600 transition">
                            {previewId === f.file_id ? 'Hide' : 'Preview'}
                          </button>
                          <button onClick={() => download(f.file_id)} className="bg-green-500 text-white px-3 py-1 rounded-lg shadow hover:bg-green-600 transition">Download</button>
                          {f.role === 'share' && (
                            <button onClick={() => navigator.clipboard.writeText(window.location.origin+`/view/${f.file_id}`)} className="bg-yellow-500 text-white px-3 py-1 rounded-lg shadow hover:bg-yellow-600 transition">Share Link</button>
                          )}
                        </>
                      ) : f.role === 'read' ? (
                        <>
                          <input type="password" placeholder="Passkey" value={passkeyById[f.file_id]||''} onChange={e=>setPasskeyById({...passkeyById,[f.file_id]:e.target.value})} className="border p-1 rounded" />
                          <button onClick={() => setPreviewId(previewId === f.file_id ? null : f.file_id)} className="bg-blue-500 text-white px-3 py-1 rounded-lg shadow hover:bg-blue-600 transition">{previewId === f.file_id ? 'Hide' : 'View'}</button>
                        </>
                      ) : (
                        <span className="text-gray-400">Not allowed</span>
                      )}
                    </div>
                  </td>
                </tr>
                {/* Inline preview row */}
                {previewId === f.file_id && (
                  <tr className="bg-blue-50">
                    <td colSpan={5} className="px-6 pt-2 pb-7">
                      <SharedFileViewer fileId={f.file_id} originalname={f.originalname} passkey={passkeyById[f.file_id]||''} />
                    </td>
                  </tr>
                )}
                </React.Fragment>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
